def linear_alpha(t_norm: float) -> float:
    return max(0.0, min(1.0, t_norm))

def sigmoid_alpha(t_norm: float) -> float:
    return 1.0 / (1.0 + math.exp(-12.0 * (t_norm - 0.5)))

